#include <vector>
#include <queue>
#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    unordered_map<long long, vector<pair<long long, pair<long long, long long>>>> adj;
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long s = edge[2];
        long long e = edge[3];
        adj[u].emplace_back(v, make_pair(s, e));
    }

    // Priority queue for Dijkstra's algorithm: (time, node)
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    pq.emplace(0, 0);

    // Distance array to track the earliest time to reach each node
    vector<long long> dist(n, -1);
    dist[0] = 0;

    while (!pq.empty()) {
        long long time = pq.top().first;
        long long node = pq.top().second;
        pq.pop();

        // If we have already found a better time for this node, skip
        if (time > dist[node]) continue;

        // Try to move along each outgoing edge
        for (auto& [v, [s, e]] : adj[node]) {
            // Check if we can use this edge at the current time
            if (s <= time && time <= e) {
                // We can take this edge, move to node v at time + 1
                long long new_time = time + 1;
                if (dist[v] == -1 || new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.emplace(new_time, v);
                }
            }
        }

        // Option to stay at the current node
        if (node != n - 1) {
            long long new_time = time + 1;
            if (dist[node] == -1 || new_time < dist[node]) {
                dist[node] = new_time;
                pq.emplace(new_time, node);
            }
        }
    }

    return dist[n - 1] == -1 ? -1 : dist[n - 1];
}

